"use client";
import React, { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Star, Users, MapPin, Phone, Mail } from "lucide-react";

export default function Home() {
  const [location, setLocation] = useState("");
  const [cleaners, setCleaners] = useState([
    {
      id: 1,
      name: "Cleaner 1",
      rating: 4.5,
      jobs: 120,
      location: "Hanoi",
      phone: "0123-456-789",
      email: "cleaner1@example.com",
      image: "https://via.placeholder.com/150",
    },
    {
      id: 2,
      name: "Cleaner 2",
      rating: 4.8,
      jobs: 200,
      location: "Ho Chi Minh City",
      phone: "0987-654-321",
      email: "cleaner2@example.com",
      image: "https://via.placeholder.com/150",
    },
    {
      id: 3,
      name: "Cleaner 3",
      rating: 4.3,
      jobs: 90,
      location: "Da Nang",
      phone: "0112-233-344",
      email: "cleaner3@example.com",
      image: "https://via.placeholder.com/150",
    },
  ]);

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hero Section */}
      <section className="bg-gradient-to-r from-blue-500 to-indigo-600 text-white py-16 px-6 text-center">
        <h1 className="text-4xl font-bold mb-4">Find Your Trusted Cleaner</h1>
        <p className="text-lg mb-6">
          Book professional cleaners near you in just a few clicks
        </p>
        <div className="flex max-w-md mx-auto bg-white rounded-2xl overflow-hidden shadow-lg">
          <Input
            placeholder="Enter your location..."
            value={location}
            onChange={(e) => setLocation(e.target.value)}
            className="flex-1 border-0 focus-visible:ring-0 text-gray-800"
          />
          <Button className="bg-indigo-600 text-white rounded-none rounded-r-2xl">
            Search
          </Button>
        </div>
      </section>

      {/* Cleaner List */}
      <section className="py-12 px-6 max-w-6xl mx-auto">
        <h2 className="text-2xl font-semibold mb-8 text-center">
          Available Cleaners
        </h2>
        <div className="grid gap-6 md:grid-cols-3">
          {cleaners.map((cleaner) => (
            <Card
              key={cleaner.id}
              className="shadow-md rounded-2xl overflow-hidden hover:shadow-xl transition"
            >
              <img
                src={cleaner.image}
                alt={cleaner.name}
                className="w-full h-40 object-cover"
              />
              <CardContent className="p-4">
                <h3 className="text-lg font-semibold">{cleaner.name}</h3>
                <div className="flex items-center gap-2 text-yellow-500 mt-1">
                  <Star size={16} fill="currentColor" />
                  <span>{cleaner.rating}</span>
                  <Badge variant="secondary">{cleaner.jobs} jobs</Badge>
                </div>
                <div className="mt-3 space-y-1 text-gray-600 text-sm">
                  <p className="flex items-center gap-2">
                    <MapPin size={16} /> {cleaner.location}
                  </p>
                  <p className="flex items-center gap-2">
                    <Phone size={16} /> {cleaner.phone}
                  </p>
                  <p className="flex items-center gap-2">
                    <Mail size={16} /> {cleaner.email}
                  </p>
                </div>
                <Button className="w-full mt-4 bg-green-500 hover:bg-green-600 text-white">
                  Book Now
                </Button>
              </CardContent>
            </Card>
          ))}
        </div>
      </section>
    </div>
  );
}
